sqlReaderQuery.value:
@concat('SELECT * FROM [dbo].[CultureResource] WITH (NOLOCK) 
         WHERE CultureResourceId >= ', item().StartID, ' 
         AND CultureResourceId < ', item().EndID)

@if(equals(pipeline().parameters.TableList, '*'), 
    'SELECT QUOTENAME(s.name) + ''.'' + QUOTENAME(t.name) AS TableName, s.name AS SchemaName, t.name AS TableNameOnly FROM sys.tables t INNER JOIN sys.schemas s ON t.schema_id = s.schema_id WHERE t.is_ms_shipped = 0 AND t.name NOT LIKE ''Bak_%'' AND t.name NOT LIKE ''%_backup'' AND t.name NOT LIKE ''%_bak'' AND t.name NOT LIKE ''%_old'' ORDER BY s.name, t.name',
    concat('SELECT value AS TableName, CASE WHEN CHARINDEX(''.'', value) > 0 THEN PARSENAME(REPLACE(REPLACE(value, ''['', ''''), '']'', ''''), 2) ELSE ''dbo'' END AS SchemaName, CASE WHEN CHARINDEX(''.'', value) > 0 THEN PARSENAME(REPLACE(REPLACE(value, ''['', ''''), '']'', ''''), 1) ELSE REPLACE(REPLACE(value, ''['', ''''), '']'', '''') END AS TableNameOnly FROM STRING_SPLIT(''', pipeline().parameters.TableList, ''', '','') WHERE LEN(LTRIM(RTRIM(value))) > 0')
)
